var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"더는 오지 않는 것 같네요.","JPN":"これ以上はもう来ないようですね。","ENG":"I think that's all of them.","TWN":"應該沒了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"할아범은 무사해?","JPN":"おじいちゃんは平気？","ENG":"Are you okay, Kian?","TWN":"奇恩爺爺你沒事吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"예, 저는 안전한 곳에 숨어있었습니다. 아가씨.","JPN":"ええ、お嬢様。私は安全なところに隠れていましたので。","ENG":"Yes. I was hiding in a safe place, Miss Morgana.","TWN":"我沒事，小姐，我有躲在安全的地方。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그나저나 걱정이군요. 그루터기와 그리 멀지 않은 곳에 마물이 어슬렁대다니.","JPN":"それにしても、心配ですね。切り株からそこまで離れていないところに魔物がうろついているなんて。","ENG":"But this is concerning. Seeing so many monsters crawling not so far away from the Stump.","TWN":"…不過真讓人擔心呢，怪物竟然在離木墩不遠的地方徘徊。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"저희가 자릴 비운 사이에 마을이 또 놈들의 습격을 받으면 어쩌죠?","JPN":"私たちが村を離れている隙に、またやつらの襲撃を受けたら大変です。","ENG":"What if they attack the village again while we are away?","TWN":"要是我們離開的這段時間，村子又被那些傢伙襲擊怎麼辦？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"쓸데없는 걱정이야. 그루터기엔 멀린이 있으니까.","JPN":"無駄な心配よ。切り株にはマーリンがいるじゃない。","ENG":"No need to worry. The Stump has Merlin.","TWN":"這不用擔心，木墩那邊有梅林在。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"멀린 씨도 모르가나가 믿고 있을 만큼 강한 분인가보네요.","JPN":"モルガナさんが信頼するほどマーリンさんは強いお方なんですね。","ENG":"It seems Merlin is strong enough for Morgana to trust her.","TWN":"你這麼信任梅林，看來梅林也強呢。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"당연히 강하지. 멀린은 전생에 아발론을 수호하던 왕이었으니까.","JPN":"もちろん強いよ。マーリンは前世ではアバロンを守護する王だったんだから。","ENG":"Of course, she's strong. Merlin was the king who protected Avalon in her past life.","TWN":"那當然，梅林前世可是守護阿瓦隆的王。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"왕의 영혼은 황금나무의 축복을 받았기 때문에 반드시 성자로 태어나거든.","JPN":"王の魂は黄金の木の祝福を受けていて、必ず聖者として生まれ変わることになっているの。","ENG":"A king's soul blessed by the Golden Tree always rebirths as a Helgon.","TWN":"王的靈魂受到黃金樹的祝福，所以必定會轉世為聖者。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네…? 멀린 씨가 저희랑 같은 성자였나요?","JPN":"え……？　マーリンさんは私たちと同じ聖者だったんですか？","ENG":"What...? Then Merlin is also a Helgon like us?","TWN":"是嗎…？梅林和我們一樣是聖者？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"딱히 놀랄 것도 없잖아.","JPN":"別に驚くようなことではないでしょ。","ENG":"What are you so surprised about?","TWN":"有什麼好驚訝的？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그럼 성자도 아닌 평범한 인간이 어떻게 늙지도 않고 천 년을 넘게 살겠어?","JPN":"じゃあ聖者でもない普通の人間が、どうやって千年も老いることなく生きていられると思ったのよ？","ENG":"How can an ordinary person who's not even a Helgon live to be over a thousand years old and not age?","TWN":"如果她不是聖者只是個普通人，怎麼可能長生不老？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아무튼 서둘러. 우린 아직 갈 길이 멀다구.","JPN":"まあとにかく、今は急ぎましょう。まだ道程は長いんだから。","ENG":"Anyway, we have to hurry. We still have a long ways to go.","TWN":"總之，動作快。我們還有很長的路要走。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"알겠습니다, 아가씨.","JPN":"かしこまりました、お嬢様。","ENG":"Understood, Miss Morgana.","TWN":"好的，小姐。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};